pool-factory-functions-object-pooling.code:
create_rock = {
  rock1 => sphere: pos(-4+rnd(8),0,0), material="pond"
  return rock1
}

rocks_pool => Object.Pool(create_rock, size 5)

show_rock = { 
  var rock = rocks_pool.acquire
  do async 
    rock.move left 1+rnd(5) in 1+rnd(2) seconds 
    rock.delete
  end do  
}

run show_rock every 1 seconds

